lid status code, please try again later.\");\n        end\n    end\n    \n    --!optimize 2\n    local getFlag = function(name)\n        local nonce = generateNonce();\n        local endpoint = host .. \"/public/flag/\" .. fToString(service) .. \"?name=\" .. name;\n    \n        if useNonce then\n            endpoint = endpoint .. \"&nonce=\" .. nonce;\n        end\n    \n        local response = fRequest({\n            Url = endpoint,\n            Method = \"GET\",\n        });\n    \n        if response.StatusCode == 200 then\n            local decoded = lDecode(response.Body);\n    \n            if decoded.success == true then\n                if useNonce then\n                    if decoded.data.hash == lDigest(fToString(decoded.data.value) .. \"-\" .. nonce .. \"-\" .. secret) then\n                        return decoded.data.value;\n                    else\n                        onMessage(\"failed to verify integrity.\");\n                        return nil;\n                    end\n                else\n                    return decoded.data.value;\n                end\n            else\n                onMessage(decoded.message);\n                return nil;\n            end\n        else\n            return nil;\n        end\n    end\n    \n    \n    return {\n        Verify = verifyKey,\n        GetFlag = getFlag,\n        Copy = copyLink,\n    }\nend\n\n\nreturn Platoboost"
local cache = {}

local function resolvePath(basePath, relativePath)
    relativePath = relativePath:gsub("\\", "/")
    if relativePath:sub(1, 2) == "./" then
        relativePath = relativePath:sub(3)
    end
    
    local baseParts = {}
    for part in basePath:gmatch("[^/]+") do
        table.insert(baseParts, part)
    end
    
    local relParts = {}
    for part in relativePath:gmatch("[^/]+") do
        table.insert(relParts, part)
    end
    
    for _, part in ipairs(relParts) do
        if part == ".." then
            if #baseParts > 0 then
                table.remove(baseParts)
            end
        elseif part ~= "." then
            table.insert(baseParts, part)
        end
    end
    
    return table.concat(baseParts, "/")
end

local function customRequire(path, currentDir)
    if path == "../build/package" or path == "build/package" then
        return '{"version": "1.6.65", "name": "windui"}'
    end
    
    local absolutePath = resolvePath(currentDir, path)
    if not absolutePath:match("%.lua$") then
        absolutePath = absolutePath .. ".lua"
    end
    
    if cache[absolutePath] then
        return cache[absolutePath]
    end
    
    local content = BundledFiles[absolutePath]
    if not content then
        local folderInitPath = absolutePath:gsub("%.lua$", "/Init.lua")
        content = BundledFiles[folderInitPath]
        if content then
            absolutePath = folderInitPath
        else
            error("[WindUI Loader] Failed to load module: " .. path .. " (resolved as " .. absolutePath .. ")")
        end
    end
    
    local newCurrentDir = ""
    local parts = {}
    for part in absolutePath:gmatch("[^/]+") do
        table.insert(parts, part)
    end
    if #parts > 1 then
        table.remove(parts)
        newCurrentDir = table.concat(parts, "/") .. "/"
    end
    
    local func, err = loadstring(content, "=" .. absolutePath)
    if not func then
        error("[WindUI Loader] Syntax error in module " .. absolutePath .. ": " .. tostring(err))
    end
    
    local env = setmetatable({
        require = function(targetPath)
            return customRequire(targetPath, newCurrentDir)
        end
    }, { __index = getfenv(0) })
    
    setfenv(func, env)
    
    local moduleResult = func()
    cache[absolutePath] = moduleResult
    return moduleResult
end

return customRequire("Init.lua", "")
